const logoBase64 = "data:image/png;base64,";
// PDF Generation Module for School Vehicle Booking System
// Uses html2pdf.js CDN to generate clean, print-ready formal PDF documents

const pdfGenerator = {
    generateBookingPDF: function(bookingId) {
        // Fetch booking data
        const booking = db.getBookingById(bookingId);
        if (!booking) {
            alert('ไม่พบข้อมูลคำขอใช้รถยนต์');
            return;
        }

        // Fetch assignment if any
        const assignments = db.getAssignments();
        const assignment = assignments.find(a => a.booking_id === booking.id);
        
        let isSchoolCar = false;
        let isHiredCar = false;
        let vehicleLicense = '................................................';
        let driverName = '................................................';
        
        if (assignment) {
            const vehicle = db.getVehicles().find(v => v.id === assignment.vehicle_id);
            const driver = db.getDrivers().find(d => d.id === assignment.driver_id);
            
            if (vehicle) {
                vehicleLicense = vehicle.license_plate;
                if (vehicle.type === 'other' || vehicle.id === 6) {
                    isHiredCar = true;
                } else {
                    isSchoolCar = true;
                }
            }
            if (driver) {
                driverName = driver.full_name;
            }
        }

        // Fetch department
        const departments = db.getDepartments();
        const dept = departments.find(d => d.id === booking.department_id);
        const deptName = dept ? dept.name : '................................................';

        // Format dates
        const months = [
            'มกราคม', 'กุมภาพันธ์', 'มีนาคม', 'เมษายน', 'พฤษภาคม', 'มิถุนายน',
            'กรกฎาคม', 'สิงหาคม', 'กันยายน', 'ตุลาคม', 'พฤศจิกายน', 'ธันวาคม'
        ];

        const formatThaiDate = (dateStr) => {
            if (!dateStr) return '........................';
            const date = new Date(dateStr);
            const day = date.getDate();
            const month = months[date.getMonth()];
            const year = date.getFullYear() + 543;
            return `${day} ${month} พ.ศ. ${year}`;
        };

        const startDate = new Date(booking.start_date_time);
        const endDate = new Date(booking.end_date_time);
        
        const startDay = startDate.getDate();
        const startMonth = months[startDate.getMonth()];
        const startYear = startDate.getFullYear() + 543;
        const startHour = String(startDate.getHours()).padStart(2, '0');
        const startMin = String(startDate.getMinutes()).padStart(2, '0');

        const endDay = endDate.getDate();
        const endMonth = months[endDate.getMonth()];
        const endYear = endDate.getFullYear() + 543;
        const endHour = String(endDate.getHours()).padStart(2, '0');
        const endMin = String(endDate.getMinutes()).padStart(2, '0');

        const startDayFormatted = `${startDay}`;
        const endDayFormatted = `${endDay}`;
        const startHourFormatted = `${startHour}.${startMin}`;
        const endHourFormatted = `${endHour}.${endMin}`;

        const isSameDay = startDate.toDateString() === endDate.toDateString();

        // Determine purpose type
        const objText = booking.objective.toLowerCase();
        let isCoord = false;
        let isMeeting = false;
        let isSeminar = false;
        let isOther = false;
        let otherText = '';

        if (objText.includes('ติดต่อ') || objText.includes('ประสานงาน')) {
            isCoord = true;
        } else if (objText.includes('ประชุม')) {
            isMeeting = true;
        } else if (objText.includes('อบรม') || objText.includes('สัมมนา')) {
            isSeminar = true;
        } else {
            isOther = true;
            otherText = booking.objective;
        }

        // Try to parse teachers and students robustly
        let teacherCount = 0;
        let studentCount = 0;
        const details = booking.passenger_details || '';
        
        // 1. Look for explicit mentions in passenger details
        const teacherExpMatch = details.match(/(?:ครู|ครูผู้ควบคุม|ครูผู้ดูแล|ครูผู้ประสานงาน|อาจารย์)\s*(?:จำนวน)?\s*(\d+)\s*(?:คน|ท่าน)/i);
        const studentExpMatch = details.match(/(?:นักเรียน|เด็ก|ผู้เรียน)\s*(?:จำนวน)?\s*(\d+)\s*คน/i);
        
        if (teacherExpMatch) {
            teacherCount = parseInt(teacherExpMatch[1]);
        }
        if (studentExpMatch) {
            studentCount = parseInt(studentExpMatch[1]);
        }
        
        // 2. Line-by-line fallback parsing if counts are still 0
        if (teacherCount === 0 || studentCount === 0) {
            const lines = details.split('\n');
            let lineTeacherCount = 0;
            let lineStudentCount = 0;
            
            lines.forEach(line => {
                const cleanLine = line.trim();
                if (!cleanLine) return;
                
                if (cleanLine.includes('ครู') || cleanLine.includes('อาจารย์')) {
                    lineTeacherCount++;
                } else if (cleanLine.includes('ด.ช.') || cleanLine.includes('ด.ญ.') || cleanLine.includes('เด็กชาย') || cleanLine.includes('เด็กหญิง') || cleanLine.includes('นักเรียน')) {
                    lineStudentCount++;
                }
            });
            
            if (teacherCount === 0 && lineTeacherCount > 0) {
                teacherCount = lineTeacherCount;
            }
            if (studentCount === 0 && lineStudentCount > 0) {
                studentCount = lineStudentCount;
            }
        }
        
        // 3. Fallback to total count if still 0
        if (teacherCount === 0 && studentCount === 0) {
            const total = parseInt(booking.passenger_count) || 0;
            if (total > 0) {
                if (details.includes('ครู') || details.includes('ท่าน')) {
                    teacherCount = total;
                    studentCount = 0;
                } else {
                    teacherCount = 1; // Requester
                    studentCount = Math.max(0, total - 1);
                }
            }
        }

        // Define status and position variables
        const position = booking.requester_position || '................................';
        const isApproved = booking.status === 'approved' || booking.status === 'completed';
        const isRejected = booking.status === 'rejected';

        // Create HTML element to print
        const element = document.createElement('div');
        element.style.padding = '10px 25px';
        element.style.fontFamily = "'TH Sarabun PSK', 'THSarabunNew', 'Sarabun', sans-serif";
        element.style.color = '#000';
        element.style.backgroundColor = '#fff';
        element.style.fontSize = '15px';
        element.style.lineHeight = '1.45';
        element.style.width = '700px'; // Standard A4 width in px for pdf rendering
        element.style.boxSizing = 'border-box';

        // Inline stylesheet for custom print rendering
        element.innerHTML = `
            <style>
                .memo-header {
                    position: relative;
                    text-align: center;
                    margin-bottom: 8px;
                    height: 55px;
                }
                .memo-logo {
                    position: absolute;
                    left: 0;
                    top: -5px;
                    width: 50px;
                    height: 50px;
                    object-fit: contain;
                }
                .memo-title {
                    font-size: 24px;
                    font-weight: bold;
                    margin: 0;
                    line-height: 55px;
                }
            </style>
            
            <!-- Memo Header Section -->
            <div class="memo-header">
                <img src="${logoBase64}" class="memo-logo" alt="School Logo">
                <h1 class="memo-title">บันทึกข้อความ</h1>
            </div>
            
            <!-- Metadata Section -->
            <div style="margin-bottom: 4px; font-size: 15px;">
                <span style="font-weight: bold; width: 80px; display: inline-block;">ส่วนราชการ</span>
                <span>โรงเรียนมัธยมวชิราลงกรณวราราม สพม.นครราชสีมา</span>
            </div>
            
            <div style="margin-bottom: 4px; font-size: 15px; display: flex; justify-content: space-between;">
                <div style="flex-grow: 1; display: flex;">
                    <span style="font-weight: bold; width: 30px;">ที่</span>
                    <span style="flex-grow: 1; border-bottom: 1px dotted #000; padding-left: 5px; padding-bottom: 2px; font-weight: bold; min-width: 150px;">${booking.booking_reference}</span>
                </div>
                <div style="width: 350px; display: flex; margin-left: 20px;">
                    <span style="font-weight: bold; width: 50px; text-align: center;">วันที่</span>
                    <span style="flex-grow: 1; border-bottom: 1px dotted #000; padding-left: 5px; padding-bottom: 2px; font-weight: bold;">${formatThaiDate(booking.created_at)}</span>
                </div>
            </div>
            
            <div style="margin-bottom: 6px; font-size: 15px; padding-bottom: 2px; border-bottom: 2px solid #000;">
                <span style="font-weight: bold; width: 50px; display: inline-block;">เรื่อง</span>
                <span style="font-weight: bold;">ขออนุญาตใช้รถยนต์ส่วนกลางของโรงเรียนไปราชการ</span>
            </div>

            <div style="margin-bottom: 6px; font-size: 15px;">
                <span style="font-weight: bold; margin-right: 8px;">เรียน</span> ผู้อำนวยการโรงเรียนมัธยมวชิราลงกรณวราราม
            </div>

            <!-- Body Section -->
            <div style="text-indent: 40px; margin-bottom: 4px; text-align: justify; line-height: 1.45;">
                ด้วยข้าพเจ้า (นาย / นาง /นางสาว /ยศ) <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 8px 2px 8px;">${booking.requester_name}</span>
                ตำแหน่ง <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 8px 2px 8px;">${position}</span> กลุ่มสาระการเรียนรู้ / กลุ่มงาน <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 8px 2px 8px;">${deptName}</span>
                มีความประสงค์ขอใช้รถยนต์ส่วนกลางของโรงเรียน เพื่อ
            </div>

            <div style="margin-left: 40px; margin-bottom: 4px; display: flex; flex-direction: column; gap: 1px; line-height: 1.45;">
                <div>
                    <span>${isCoord ? '(✓)' : '( &nbsp; )'}</span> ไปติดต่อประสานงานราชการ
                    &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                    <span>${isMeeting ? '(✓)' : '( &nbsp; )'}</span> ประชุม
                </div>
                <div>
                    <span>${isSeminar ? '(✓)' : '( &nbsp; )'}</span> อบรม / สัมมนา
                    &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                    <span>${isOther ? '(✓)' : '( &nbsp; )'}</span> อื่นๆ (โปรดระบุ) <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 8px 2px 8px;">${otherText || '....................................................................'}</span>
                </div>
            </div>

            <div style="text-indent: 40px; margin-bottom: 4px; text-align: justify; line-height: 1.45;">
                จำนวนผู้โดยสาร ครู <span style="font-weight: bold; padding: 0 10px 2px 10px; border-bottom: 1px dotted #000;">${teacherCount}</span> คน 
                นักเรียน <span style="font-weight: bold; padding: 0 10px 2px 10px; border-bottom: 1px dotted #000;">${studentCount}</span> คน 
                ณ (โปรดระบุสถานที่) <span style="font-weight: bold; padding: 0 10px 2px 10px; border-bottom: 1px dotted #000;">${booking.destination}</span>
            </div>

            <div style="margin-bottom: 4px; text-align: justify; line-height: 1.45;">
                ในวันที่ <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${startDayFormatted}</span> 
                เดือน <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${startMonth}</span> 
                พ.ศ. <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${startYear}</span> 
                เวลา <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${startHourFormatted}</span> น. 
                ถึง เวลา <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${isSameDay ? endHourFormatted : '24.00'}</span> น.
            </div>
            
            <div style="margin-bottom: 4px; text-align: justify; line-height: 1.45;">
                ถึงวันที่ <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${endDayFormatted}</span> 
                เดือน <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${endMonth}</span> 
                พ.ศ. <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${endYear}</span> 
                เวลา <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${isSameDay ? startHourFormatted : '00.00'}</span> น. 
                ถึง เวลา <span style="font-weight: bold; padding: 0 8px 2px 8px; border-bottom: 1px dotted #000;">${endHourFormatted}</span> น.
            </div>

            <div style="margin-bottom: 6px; line-height: 1.45;">
                โดยใช้น้ำมันเชื้อเพลิงจาก &nbsp;&nbsp;
                <span>(✓)</span> ส่วนกลาง &nbsp;&nbsp;
                <span>( &nbsp; )</span> ส่วนตัว &nbsp;&nbsp;
                <span>( &nbsp; )</span> อื่นๆ (โปรดระบุ) ........................................
            </div>

            <div style="text-indent: 40px; margin-bottom: 4px;">
                จึงเรียนมาเพื่อโปรดพิจารณา
            </div>

            <!-- Requester Signature -->
            <div style="display: flex; justify-content: flex-end; margin-bottom: 8px; padding-right: 20px;">
                <div style="text-align: center; width: 250px; line-height: 1.45;">
                    <br>ลงชื่อ ..........................................<br>
                    ( <span style="font-weight: bold;">${booking.requester_name}</span> )<br>
                    ผู้ขอใช้รถ
                </div>
            </div>

            <!-- Section 2: Vehicle Head Opinion -->
            <div style="padding: 4px 0; margin-bottom: 8px; border-top: 1px solid #000; padding-top: 4px;">
                <h4 style="font-size: 15px; font-weight: bold; margin: 0 0 2px 0;">ความคิดเห็นของหัวหน้างานยานพาหนะและบริการสาธารณะ</h4>
                <div style="margin-bottom: 2px; font-size: 15px; line-height: 1.45;">
                    <span>${isSchoolCar ? '(✓)' : '( &nbsp; )'}</span> มอบหมายหน้าที่ให้ <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 8px 2px 8px;">${isSchoolCar ? driverName : '................................................'}</span> เป็นพนักงานขับรถ 
                    และใช้รถยนต์หมายเลขทะเบียน <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 8px 2px 8px;">${isSchoolCar ? vehicleLicense : '................................................'}</span>
                </div>
                <div style="margin-bottom: 4px; font-size: 15px; line-height: 1.45;">
                    <span>${isHiredCar ? '(✓)' : '( &nbsp; )'}</span> รถโรงเรียนไม่ว่าง ให้ไปรถรับจ้างตามระเบียบสำนักนายกฯ
                </div>
                <div style="display: flex; justify-content: flex-end; padding-right: 20px;">
                    <div style="text-align: center; width: 250px; font-size: 15px; line-height: 1.45;">
                        <br>ลงชื่อ ..........................................<br>
                        ( นายสิรวิชญ์ หล้าพันธ์ )<br>
                        หัวหน้างานยานพาหนะ
                    </div>
                </div>
            </div>

            <!-- Section 3: Approver & Director Order side-by-side -->
            <div style="display: flex; justify-content: space-between; gap: 20px; border-top: 1px solid #000; padding-top: 4px;">
                <!-- Left Box: Deputy Director -->
                <div style="width: 50%; display: flex; flex-direction: column; justify-content: space-between; min-height: 100px;">
                    <div>
                        <h4 style="font-size: 15px; font-weight: bold; margin: 0 0 2px 0;">ความคิดเห็นของรองผู้อำนวยการกลุ่มบริหารทั่วไป</h4>
                        <div style="font-size: 14px; line-height: 1.45; display: flex; flex-direction: column; gap: 1px;">
                            <div><span>${isApproved ? '(✓)' : '( &nbsp; )'}</span> เสนอเพื่อโปรดพิจารณา</div>
                            <div><span>${isApproved ? '(✓)' : '( &nbsp; )'}</span> เห็นสมควรอนุญาต</div>
                            <div><span>${isRejected ? '(✓)' : '( &nbsp; )'}</span> ไม่อนุญาต เนื่องจาก <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 4px 2px 4px;">${isRejected ? booking.rejection_reason : '................................'}</span></div>
                        </div>
                    </div>
                    <div style="text-align: center; font-size: 15px; margin-top: 6px; line-height: 1.45;">
                        <br>ลงชื่อ ..........................................<br>
                        ( นายสุรวุฒิ ซอกรัมย์ )<br>
                        รองผู้อำนวยการกลุ่มบริหารทั่วไป
                    </div>
                </div>

                <!-- Right Box: Director -->
                <div style="width: 50%; display: flex; flex-direction: column; justify-content: space-between; min-height: 100px;">
                    <div>
                        <h4 style="font-size: 15px; font-weight: bold; margin: 0 0 2px 0;">คำสั่งของผู้อำนวยการโรงเรียน</h4>
                        <div style="font-size: 14px; line-height: 1.45; display: flex; flex-direction: column; gap: 1px;">
                            <div><span>${isApproved ? '(✓)' : '( &nbsp; )'}</span> ทราบ</div>
                            <div><span>${isApproved ? '(✓)' : '( &nbsp; )'}</span> อนุญาต</div>
                            <div><span>${isRejected ? '(✓)' : '( &nbsp; )'}</span> ไม่อนุญาต เนื่องจาก <span style="font-weight: bold; border-bottom: 1px dotted #000; padding: 0 4px 2px 4px;">${isRejected ? booking.rejection_reason : '................................'}</span></div>
                        </div>
                    </div>
                    <div style="text-align: center; font-size: 15px; margin-top: 6px; line-height: 1.45;">
                        <br>ลงชื่อ ..........................................<br>
                        ( นายอิสรา รักชาติ )<br>
                        ผู้อำนวยการโรงเรียนมัธยมวชิราลงกรณวราราม
                    </div>
                </div>
            </div>
        `;

        // Configure PDF rendering options
        const opt = {
            margin:       10,
            filename:     `ใบขอใช้รถ_${booking.booking_reference}.pdf`,
            image:        { type: 'jpeg', quality: 0.98 },
            html2canvas:  { scale: 2, useCORS: true },
            jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
        };

        // Render as PDF
        document.body.appendChild(element);
        
        if (typeof html2pdf !== 'undefined') {
            html2pdf().set(opt).from(element).save().then(() => {
                document.body.removeChild(element);
            }).catch(err => {
                console.error(err);
                document.body.removeChild(element);
                alert('เกิดข้อผิดพลาดในการสร้าง PDF กรุณาลองใหม่อีกครั้ง');
            });
        } else {
            const printWin = window.open('', '_blank');
            printWin.document.write('<html><head><title>Print Request</title>');
            printWin.document.write('<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/5.15.4/css/all.min.css">');
            printWin.document.write('<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/font-th-sarabun-new@1.0.0/css/th-sarabun-new.min.css">');
            printWin.document.write('<link href="https://fonts.googleapis.com/css2?family=Sarabun:wght@400;700&display=swap" rel="stylesheet">');
            printWin.document.write('<style>body { font-family: "TH Sarabun PSK", "THSarabunNew", "Sarabun", sans-serif; padding: 20px; }</style>');
            printWin.document.write('</head><body>');
            printWin.document.write(element.innerHTML);
            printWin.document.close();
            printWin.print();
            document.body.removeChild(element);
        }
    }
};
